import { Mesh, Program, Renderer, Triangle } from 'ogl';
import { useDeferredValue, useEffect, useRef } from 'react';

import { cn } from '@/lib/utils';
import { mergeRefs, useInView, usePrefersReducedMotion } from '@/lib/containment';

// ─── GLSL ────────────────────────────────────────────────────────────────────

const VERT = `#version 300 es
in vec2 position;
void main() { gl_Position = vec4(position, 0.0, 1.0); }`;

const FRAG = `#version 300 es
precision highp float;

uniform float uTime;
uniform float uAmplitude;
uniform vec3  uColorStops[3];
uniform vec2  uResolution;
uniform float uBlend;
uniform float uSpeed;

out vec4 fragColor;

vec3 permute(vec3 x) { return mod(((x * 34.0) + 1.0) * x, 289.0); }

float snoise(vec2 v) {
  const vec4 C = vec4(0.211324865405187, 0.366025403784439, -0.577350269189626, 0.024390243902439);
  vec2 i   = floor(v + dot(v, C.yy));
  vec2 x0  = v - i + dot(i, C.xx);
  vec2 i1  = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
  vec4 x12 = x0.xyxy + C.xxzz;
  x12.xy  -= i1;
  i = mod(i, 289.0);
  vec3 p  = permute(permute(i.y + vec3(0.0, i1.y, 1.0)) + i.x + vec3(0.0, i1.x, 1.0));
  vec3 m  = max(0.5 - vec3(dot(x0, x0), dot(x12.xy, x12.xy), dot(x12.zw, x12.zw)), 0.0);
  m = m * m * m * m;
  vec3 x  = 2.0 * fract(p * C.www) - 1.0;
  vec3 h  = abs(x) - 0.5;
  vec3 ox = floor(x + 0.5);
  vec3 a0 = x - ox;
  m *= 1.79284291400159 - 0.85373472095314 * (a0 * a0 + h * h);
  vec3 g;
  g.x  = a0.x  * x0.x  + h.x  * x0.y;
  g.yz = a0.yz * x12.xz + h.yz * x12.yw;
  return 130.0 * dot(m, g);
}

struct ColorStop { vec3 color; float position; };

#define COLOR_RAMP(colors, factor, finalColor) {                              \
  int index = 0;                                                              \
  for (int i = 0; i < 2; i++) {                                              \
    ColorStop cc = colors[i];                                                 \
    bool between = cc.position <= factor;                                     \
    index = int(mix(float(index), float(i), float(between)));                \
  }                                                                           \
  ColorStop cc = colors[index]; ColorStop nc = colors[index + 1];            \
  float lerpF = (factor - cc.position) / (nc.position - cc.position);        \
  finalColor = mix(cc.color, nc.color, lerpF);                               \
}

void main() {
  vec2 uv = gl_FragCoord.xy / uResolution;

  ColorStop colors[3];
  colors[0] = ColorStop(uColorStops[0], 0.0);
  colors[1] = ColorStop(uColorStops[1], 0.5);
  colors[2] = ColorStop(uColorStops[2], 1.0);

  vec3 rampColor;
  COLOR_RAMP(colors, uv.x, rampColor);

  float t = uTime * uSpeed;
  float h = snoise(vec2(uv.x * 2.0 + t * 0.1, t * 0.25)) * 0.5 * uAmplitude;
  h = exp(h);
  h = uv.y * 2.0 - h + 0.2;

  float intensity   = 0.6 * h;
  float auroraAlpha = smoothstep(0.20 - uBlend * 0.5, 0.20 + uBlend * 0.5, intensity);

  fragColor = vec4(intensity * rampColor * auroraAlpha, auroraAlpha);
}`;

// ─── Helpers ─────────────────────────────────────────────────────────────────

function hexToRgb(hex: string): [number, number, number] {
	const h = hex.replace('#', '');
	return [
		parseInt(h.slice(0, 2), 16) / 255,
		parseInt(h.slice(2, 4), 16) / 255,
		parseInt(h.slice(4, 6), 16) / 255,
	];
}

// ─── Types ───────────────────────────────────────────────────────────────────

export type AuroraProps = {
	/** Class applied to the root element. */
	className?: string;
	/** First aurora color stop (6-char hex). */
	color1?: string;
	/** Middle aurora color stop (6-char hex). */
	color2?: string;
	/** Last aurora color stop (6-char hex). */
	color3?: string;
	/** Shader time scale — higher = faster bands. */
	speed?: number;
	/** Wave height multiplier. */
	amplitude?: number;
	/** Aurora edge blend softness (0–1). */
	blend?: number;
	/** React 19: passed as a regular prop — no forwardRef needed. */
	ref?: React.Ref<HTMLDivElement>;
};

// ─── Component ───────────────────────────────────────────────────────────────

/**
 * Flowing aurora wash powered by ogl WebGL simplex-noise bands. Pauses when
 * off-screen; static radial gradient when `prefers-reduced-motion` is set.
 *
 * React 19: `ref` accepted as a plain prop — no `forwardRef` wrapper.
 */
export function Aurora({
	ref,
	className,
	color1 = '#6366f1',
	color2 = '#a78bfa',
	color3 = '#6366f1',
	speed = 1.0,
	amplitude = 1.0,
	blend = 0.5,
}: AuroraProps) {
	const reducedMotion = usePrefersReducedMotion();
	const { ref: inViewRef, inView } = useInView();

	const rootRef = useRef<HTMLDivElement>(null);
	const auroraRef = useRef<HTMLDivElement>(null);

	const inViewMut = useRef(inView);
	useEffect(() => {
		inViewMut.current = inView;
	}, [inView]);

	const dColor1 = useDeferredValue(color1);
	const dColor2 = useDeferredValue(color2);
	const dColor3 = useDeferredValue(color3);

	const depsKey = `${dColor1}-${dColor2}-${dColor3}-${speed}-${amplitude}-${blend}`;

	useEffect(() => {
		if (reducedMotion) return;
		const container = auroraRef.current;
		if (!container) return;

		let renderer: Renderer;
		let rafId = 0;

		try {
			renderer = new Renderer({ alpha: true, premultipliedAlpha: true, antialias: true });
		} catch {
			return;
		}

		const gl = renderer.gl;
		gl.clearColor(0, 0, 0, 0);
		gl.enable(gl.BLEND);
		gl.blendFunc(gl.ONE, gl.ONE_MINUS_SRC_ALPHA);

		const geometry = new Triangle(gl);
		if (geometry.attributes.uv) delete geometry.attributes.uv;

		const program = new Program(gl, {
			vertex: VERT,
			fragment: FRAG,
			uniforms: {
				uTime:       { value: 0 },
				uSpeed:      { value: speed },
				uAmplitude:  { value: amplitude },
				uColorStops: { value: [hexToRgb(dColor1), hexToRgb(dColor2), hexToRgb(dColor3)] },
				uResolution: { value: [container.offsetWidth, container.offsetHeight] },
				uBlend:      { value: blend },
			},
		});

		const mesh = new Mesh(gl, { geometry, program });
		container.appendChild(gl.canvas);
		gl.canvas.className = 'absolute inset-0 block h-full w-full';

		const ro = new ResizeObserver(() => {
			const w = container.offsetWidth;
			const h = container.offsetHeight;
			renderer.setSize(w, h);
			program.uniforms.uResolution.value = [w, h];
		});
		ro.observe(container);
		renderer.setSize(container.offsetWidth, container.offsetHeight);

		function update(t: number) {
			rafId = requestAnimationFrame(update);
			if (!inViewMut.current) return;
			program.uniforms.uTime.value = t * 0.001;
			renderer.render({ scene: mesh });
		}
		rafId = requestAnimationFrame(update);

		return () => {
			cancelAnimationFrame(rafId);
			ro.disconnect();
			if (container.contains(gl.canvas)) container.removeChild(gl.canvas);
			gl.getExtension('WEBGL_lose_context')?.loseContext();
		};
	}, [depsKey, reducedMotion]);

	return (
		<div
			ref={mergeRefs(ref, inViewRef, rootRef)}
			className={cn('relative h-full w-full overflow-hidden', className)}
		>
			{/* WebGL aurora — canvas injected by effect */}
			<div ref={auroraRef} className="absolute inset-0" aria-hidden />

			{/* Reduced-motion: static radial gradient replaces WebGL */}
			{reducedMotion && (
				<div
					className="pointer-events-none absolute inset-0"
					style={{
						background: `radial-gradient(ellipse 100% 60% at 50% 100%, ${color1}2e 0%, ${color2}18 45%, transparent 65%)`,
					}}
					aria-hidden
				/>
			)}
		</div>
	);
}
